sql:
SELECT event_type
FROM network_events
WHERE plat_id = 0 AND world_id = 0;

SELECT a.area_name, ne.event_type
FROM areas a
LEFT JOIN network_events ne ON a.area_id = ne.area_id;

SELECT dashboard_id, COUNT(*) AS number_of_widgets
FROM widgets
GROUP BY dashboard_id;

SELECT * 
FROM user_sessions
WHERE session_id = '1' AND duration > '20.0';

SELECT role_name
FROM role_channels
WHERE role_id = 1;

SELECT COUNT(DISTINCT user_id) AS user_count
FROM network_events
WHERE area_id = 0;

SELECT COUNT(*)
FROM network_events
WHERE user_id = 'user123';

SELECT users.user_name, network_events.event_type
FROM users
JOIN network_events ON users.user_id = network_events.user_id;

